/// Executor for PasswordReset flow
pub struct PasswordResetFlowExecutor<H: PasswordResetStepHandler> {
    handler: Arc<H>,
}

impl<H: PasswordResetStepHandler> PasswordResetFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<PasswordResetFlowInstance, FlowError> {
        let mut instance = PasswordResetFlowInstance::new(instance_id);
        instance.status = PasswordResetFlowStatus::Running;
        instance.current_step = Some(PasswordResetFlowStep::FindUser);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut PasswordResetFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            PasswordResetFlowStep::FindUser => {
                self.handler.handle_find_user(instance).await?
            }
            PasswordResetFlowStep::CheckUserActive => {
                let next = self.handler.evaluate_check_user_active(instance).await?;
                Some(next)
            }
            PasswordResetFlowStep::InvalidatePreviousTokens => {
                self.handler.handle_invalidate_previous_tokens(instance).await?
            }
            PasswordResetFlowStep::GenerateResetToken => {
                self.handler.handle_generate_reset_token(instance).await?
            }
            PasswordResetFlowStep::SendResetEmail => {
                self.handler.handle_send_reset_email(instance).await?
            }
            PasswordResetFlowStep::LogResetRequested => {
                self.handler.handle_log_reset_requested(instance).await?
            }
            PasswordResetFlowStep::WaitForPasswordChange => {
                self.handler.handle_wait_for_password_change(instance).await?
            }
            PasswordResetFlowStep::InvalidateAllSessions => {
                self.handler.handle_invalidate_all_sessions(instance).await?
            }
            PasswordResetFlowStep::SendConfirmationEmail => {
                self.handler.handle_send_confirmation_email(instance).await?
            }
            PasswordResetFlowStep::LogResetComplete => {
                self.handler.handle_log_reset_complete(instance).await?
            }
            PasswordResetFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            PasswordResetFlowStep::LogUnknownEmail => {
                self.handler.handle_log_unknown_email(instance).await?
            }
            PasswordResetFlowStep::LogInactiveUser => {
                self.handler.handle_log_inactive_user(instance).await?
            }
            PasswordResetFlowStep::SilentComplete => {
                self.handler.handle_silent_complete(instance).await?;
                None // Terminal step
            }
            PasswordResetFlowStep::TokenExpired => {
                self.handler.handle_token_expired(instance).await?
            }
            PasswordResetFlowStep::Expired => {
                self.handler.handle_expired(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = PasswordResetFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut PasswordResetFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != PasswordResetFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut PasswordResetFlowInstance) {
        instance.status = PasswordResetFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut PasswordResetFlowInstance, error: impl Into<String>) {
        instance.status = PasswordResetFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = PasswordResetFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, PasswordResetFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = PasswordResetFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = PasswordResetFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = PasswordResetFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = PasswordResetFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}